  name: String,
  userId: String
)

class TokenGenerationService(
  sessionExpirationMinutes: Int = 30,
  tokenLength: Int = 32
) {
  private val sessions = new ConcurrentHashMap[String, SessionToken]()
  private val apiKeys = new ConcurrentHashMap[String, ApiKey]()
  private val random = new Random()

  def generateSessionToken(userId: String): SessionToken = {
    val token = generateToken()
    val now = Instant.now()
    val expiresAt = now.plusSeconds(sessionExpirationMinutes * 60)
    
    val sessionToken = SessionToken(
      token = token,
      createdAt = now,
      expiresAt = expiresAt,
      userId = userId
    )
    
    sessions.put(token, sessionToken)
    sessionToken
  }

  def generateApiKey(userId: String, name: String): ApiKey = {
    val key = generateToken()
    val now = Instant.now()
    
    val apiKey = ApiKey(
      key = key,
      createdAt = now,
      name = name,
      userId = userId
    )
    
    apiKeys.put(key, apiKey)
    apiKey
  }

  def validateSessionToken(token: String): Option[SessionToken] = {
    Option(sessions.get(token)).filter { session =>
      session.expiresAt.isAfter(Instant.now())
    }
  }

  def validateApiKey(key: String): Option[ApiKey] = {
    Option(apiKeys.get(key))
  }

  def refreshSessionToken(token: String): Option[SessionToken] = {
    validateSessionToken(token).map { session =>
      sessions.remove(token)
      generateSessionToken(session.userId)
    }
  }

  def invalidateSessionToken(token: String): Boolean = {
    sessions.remove(token) != null
  }

  def invalidateApiKey(key: String): Boolean = {
    apiKeys.remove(key) != null
  }

  def getAllSessionsForUser(userId: String): List[SessionToken] = {
    sessions.values().asScala.filter(_.userId == userId).toList
  }

  def getAllApiKeysForUser(userId: String): List[ApiKey] = {
    apiKeys.values().asScala.filter(_.userId == userId).toList
  }

  def invalidateAllSessionsForUser(userId: String): Int = {
    val userSessions = getAllSessionsForUser(userId)
    userSessions.foreach(session => sessions.remove(session.token))
    userSessions.size
  }

  def invalidateAllApiKeysForUser(userId: String): Int = {
    val userKeys = getAllApiKeysForUser(userId)
    userKeys.foreach(key => apiKeys.remove(key.key))
    userKeys.size
  }

  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expired = sessions.asScala.filter { case (_, session) =>
      session.expiresAt.isBefore(now)
    }
    expired.foreach { case (token, _) => sessions.remove(token) }
    expired.size
  }

  def getActiveSessionCount: Int = {
    val now = Instant.now()
    sessions.values().asScala.count(_.expiresAt.isAfter(now))
  }

  def getApiKeyCount: Int = apiKeys.size()

  private def generateToken(): String = {
    Random.alphanumeric.take(tokenLength).mkString
  }
}

